/**
 * Public Blog Post Detail Page
 *
 * Full article view with SEO meta tags, structured data, and BlockDisplay renderer.
 * Uses shared PublicLayout for consistent navigation.
 */

import { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { PublicLayout } from '../../components/layout/PublicLayout';
import { blogApi } from '../../services/api';
import type { BlogPostDetail, BlogPostSummary } from '../../services/api';
import BlockDisplay from '../../components/cms/BlockDisplay';
import { Clock, ArrowLeft, Tag, Calendar } from 'lucide-react';
import AuthorBio from '../../components/blog/AuthorBio';
import { BlogCTA } from '../../components/blog/BlogCTA';
import { buildBlogStructuredData } from '../../utils/blogSchemaBuilder';

const CATEGORY_LABELS: Record<string, string> = {
  'seo': 'SEO',
  'accessibility': 'Accessibility',
  'security': 'Security',
  'performance': 'Performance',
  'content-quality': 'Content Quality',
  'structured-data': 'Structured Data',
  'eeat': 'E-E-A-T',
  'aeo': 'AEO',
  'guides': 'Guides',
  'case-studies': 'Case Studies',
  'product-updates': 'Product Updates',
};

export default function PostDetailPage() {
  const { slug } = useParams<{ slug: string }>();
  const [post, setPost] = useState<BlogPostDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);
  const [relatedPosts, setRelatedPosts] = useState<BlogPostSummary[]>([]);
  const articleRef = useRef<HTMLElement>(null);

  // Ensure all <pre> elements are keyboard-accessible (WCAG 2.1.1)
  useEffect(() => {
    if (!post || !articleRef.current) return;
    const preElements = articleRef.current.querySelectorAll('pre');
    preElements.forEach((pre) => {
      if (!pre.hasAttribute('tabindex')) {
        pre.setAttribute('tabindex', '0');
        pre.setAttribute('role', 'region');
        pre.setAttribute('aria-label', 'Code example');
      }
    });
  }, [post]);

  useEffect(() => {
    if (slug) {
      loadPost(slug);
    }
  }, [slug]);

  const loadPost = async (postSlug: string) => {
    setLoading(true);
    try {
      const { data } = await blogApi.getPost(postSlug);
      setPost(data.post);
      // Fetch related posts asynchronously (non-blocking)
      blogApi.getRelatedPosts(postSlug).then(({ data: relData }) => {
        setRelatedPosts(relData.posts);
      }).catch(() => {});
    } catch (err: unknown) {
      if (err && typeof err === 'object' && 'response' in err) {
        const axiosErr = err as { response?: { status: number } };
        if (axiosErr.response?.status === 404) {
          setNotFound(true);
        }
      }
      console.error('Failed to load post:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <PublicLayout>
        <div aria-live="polite" className="sr-only">Loading article...</div>
        <article className="max-w-3xl mx-auto px-6 lg:px-20 py-12 lg:py-20">
          {/* Back link placeholder */}
          <div className="h-5 w-28 bg-slate-100 dark:bg-slate-800 rounded animate-pulse mb-10" />
          {/* Category + reading time */}
          <div className="flex items-center gap-3 mb-5">
            <div className="h-7 w-20 bg-indigo-50 dark:bg-indigo-900/20 rounded-md animate-pulse" />
            <div className="h-5 w-16 bg-slate-100 dark:bg-slate-800 rounded animate-pulse" />
          </div>
          {/* Title */}
          <div className="h-12 bg-slate-100 dark:bg-slate-800 rounded animate-pulse mb-3" />
          <div className="h-12 bg-slate-100 dark:bg-slate-800 rounded animate-pulse w-3/4 mb-4" />
          {/* Author + date */}
          <div className="flex items-center gap-4 mb-10">
            <div className="h-4 w-24 bg-slate-100 dark:bg-slate-800 rounded animate-pulse" />
            <div className="h-4 w-32 bg-slate-100 dark:bg-slate-800 rounded animate-pulse" />
          </div>
          {/* Featured image placeholder */}
          <div className="w-full rounded-xl bg-slate-100 dark:bg-slate-800 animate-pulse mb-10" style={{ aspectRatio: '1200 / 630' }} />
          {/* Content skeleton */}
          <div className="space-y-4">
            {Array.from({ length: 8 }).map((_, i) => (
              <div key={i} className="h-4 bg-slate-100 dark:bg-slate-800 rounded animate-pulse" style={{ width: `${85 + (i % 3) * 5}%` }} />
            ))}
          </div>
        </article>
      </PublicLayout>
    );
  }

  if (notFound || !post) {
    return (
      <PublicLayout>
        <div className="flex items-center justify-center py-32">
          <div className="text-center">
            <h1 className="font-display text-3xl text-slate-900 dark:text-white mb-3">Post not found</h1>
            <p className="text-slate-600 dark:text-slate-400 mb-6">The article you're looking for doesn't exist or has been removed.</p>
            <Link to="/blog" className="text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 font-medium">
              &larr; Back to blog
            </Link>
          </div>
        </div>
      </PublicLayout>
    );
  }

  const canonicalUrl = `https://kritano.com/blog/${post.slug}`;
  const structuredData = buildBlogStructuredData(post);

  // OG image must be an absolute URL for social crawlers
  const ogImage = post.featured_image_url
    ? (post.featured_image_url.startsWith('http') ? post.featured_image_url : `https://kritano.com${post.featured_image_url}`)
    : 'https://kritano.com/og-image.png';

  return (
    <PublicLayout>
      <Helmet>
        <title>{post.seo_title || post.title} | Kritano</title>
        <meta name="description" content={post.seo_description || post.excerpt} />
        {post.focus_keyword && <meta name="keywords" content={[post.focus_keyword, ...post.tags].join(', ')} />}
        <meta property="og:title" content={post.title} />
        <meta property="og:description" content={post.excerpt} />
        <meta property="og:image" content={ogImage} />
        <meta property="og:type" content="article" />
        <meta property="og:locale" content="en_GB" />
        <meta property="article:author" content="https://kritano.com/author/chris-garlick" />
        {post.published_at && <meta property="article:published_time" content={post.published_at} />}
        {post.updated_at && <meta property="article:modified_time" content={post.updated_at} />}
        {post.category && <meta property="article:section" content={CATEGORY_LABELS[post.category] || post.category} />}
        {post.tags.map(tag => (
          <meta key={tag} property="article:tag" content={tag} />
        ))}
        <link rel="canonical" href={canonicalUrl} />
        {post.featured_image_url && (
          <link
            rel="preload"
            as="image"
            href={post.featured_image_url.replace('/original/', '/webp/').replace(/\.(png|jpe?g|gif)$/i, '.webp')}
            type="image/webp"
          />
        )}
        {structuredData.map((sd, i) => (
          <script key={i} type="application/ld+json">{JSON.stringify(sd)}</script>
        ))}
      </Helmet>

      <article ref={articleRef} className="max-w-3xl mx-auto px-6 lg:px-20 py-12 lg:py-20">
        {/* Breadcrumb */}
        <Link to="/blog" className="inline-flex items-center gap-1.5 text-sm text-slate-600 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 mb-10 transition-colors">
          <ArrowLeft className="w-4 h-4" />
          Back to blog
        </Link>

        {/* Post header */}
        <header className="mb-10">
          <div className="flex items-center gap-3 mb-5">
            <Link
              to={`/blog?category=${post.category}`}
              className="text-xs font-semibold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 px-3 py-1.5 rounded-md hover:bg-indigo-100 dark:hover:bg-indigo-900/30 transition-colors uppercase tracking-wider"
            >
              {CATEGORY_LABELS[post.category] || post.category}
            </Link>
            <span className="flex items-center gap-1 text-sm text-slate-600 dark:text-slate-400">
              <Clock className="w-3.5 h-3.5" />
              {post.reading_time_minutes} min read
            </span>
          </div>

          <h1 className="font-display text-4xl lg:text-5xl text-slate-900 dark:text-white leading-tight mb-4">
            {post.title}
          </h1>

          {post.subtitle && (
            <p className="text-xl text-slate-600 dark:text-slate-400 leading-relaxed">{post.subtitle}</p>
          )}

          <div className="mt-6 flex items-center gap-4 text-sm text-slate-600 dark:text-slate-400">
            <Link to="/author/chris-garlick" className="font-medium text-slate-600 dark:text-slate-300 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors">{post.author_name}</Link>
            {post.published_at && (
              <time dateTime={new Date(post.published_at).toISOString().split('T')[0]} className="flex items-center gap-1">
                <Calendar className="w-3.5 h-3.5" />
                {new Date(post.published_at).toLocaleDateString('en-US', {
                  month: 'long', day: 'numeric', year: 'numeric'
                })}
              </time>
            )}
          </div>
        </header>

        {/* Featured image */}
        {post.featured_image_url && (() => {
          const webpUrl = post.featured_image_url
            .replace('/original/', '/webp/')
            .replace(/\.(png|jpe?g|gif)$/i, '.webp');
          const thumbUrl = post.featured_image_url
            .replace('/original/', '/thumbnails/')
            .replace(/\.(png|gif)$/i, '.jpg');
          return (
            <figure className="mb-10 -mx-4 sm:mx-0">
              <picture>
                <source srcSet={webpUrl} type="image/webp" />
                <img
                  src={post.featured_image_url}
                  srcSet={`${thumbUrl} 400w, ${post.featured_image_url} 1200w`}
                  sizes="(max-width: 640px) 100vw, (max-width: 1024px) 90vw, 768px"
                  alt={post.featured_image_alt || `Featured image for ${post.title}`}
                  className="w-full h-auto rounded-xl"
                  style={{ aspectRatio: '1200 / 630' }}
                  loading="eager"
                  fetchPriority="high"
                  width={1200}
                  height={630}
                />
              </picture>
            </figure>
          );
        })()}

        {/* Content blocks */}
        <div className="prose prose-lg prose-slate dark:prose-invert max-w-none
          prose-headings:font-bold prose-headings:text-slate-900 dark:prose-headings:text-white
          prose-p:text-slate-600 dark:prose-p:text-slate-400 prose-p:leading-relaxed
          prose-a:text-indigo-600 dark:prose-a:text-indigo-400 prose-a:underline prose-a:decoration-indigo-300 dark:prose-a:decoration-indigo-500/50 prose-a:underline-offset-2 hover:prose-a:decoration-indigo-600
          prose-img:rounded-lg prose-pre:bg-slate-900
        " style={{ contentVisibility: 'auto', containIntrinsicSize: 'auto 2000px' }}>
          {post.content.map(block => (
            <BlockDisplay key={block.id} block={block} />
          ))}
        </div>

        {/* Tags */}
        {post.tags.length > 0 && (
          <div className="mt-12 pt-8 border-t border-slate-200 dark:border-slate-700">
            <div className="flex items-center gap-2 flex-wrap">
              <Tag className="w-4 h-4 text-slate-600 dark:text-slate-400" />
              {post.tags.map(tag => (
                <Link
                  key={tag}
                  to={`/blog?tag=${tag}`}
                  className="text-sm text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 px-3 py-1 rounded-full transition-colors"
                >
                  #{tag}
                </Link>
              ))}
            </div>
          </div>
        )}

        {/* Author bio */}
        <div className="mt-12 pt-8 border-t border-slate-200 dark:border-slate-700">
          <AuthorBio />
        </div>

        {/* Related posts */}
        {relatedPosts.length > 0 && (
          <div className="mt-12 pt-8 border-t border-slate-200 dark:border-slate-700">
            <h2 className="font-display text-2xl text-slate-900 dark:text-white mb-6">Related Articles</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {relatedPosts.map(related => (
                <Link
                  key={related.id}
                  to={`/blog/${related.slug}`}
                  className="group bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg overflow-hidden hover:shadow-md transition-shadow"
                >
                  {related.featured_image_url && (() => {
                    const webpUrl = related.featured_image_url
                      .replace('/original/', '/webp/')
                      .replace(/\.(png|jpe?g|gif)$/i, '.webp');
                    const thumbUrl = related.featured_image_url
                      .replace('/original/', '/thumbnails/')
                      .replace(/\.(png|gif)$/i, '.jpg');
                    return (
                      <picture>
                        <source srcSet={webpUrl} type="image/webp" />
                        <img
                          src={related.featured_image_url}
                          srcSet={`${thumbUrl} 400w, ${related.featured_image_url} 640w`}
                          sizes="(max-width: 768px) 100vw, 33vw"
                          alt=""
                          role="presentation"
                          className="w-full h-40 object-cover"
                          loading="lazy"
                          width={400}
                          height={160}
                        />
                      </picture>
                    );
                  })()}
                  <div className="p-4">
                    <span className="text-xs font-semibold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider">
                      {CATEGORY_LABELS[related.category] || related.category}
                    </span>
                    <h3 className="mt-1.5 font-semibold text-slate-900 dark:text-white group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors line-clamp-2">
                      {related.title}
                    </h3>
                    <p className="mt-1.5 text-sm text-slate-600 dark:text-slate-400 line-clamp-2">
                      {related.excerpt}
                    </p>
                    <div className="mt-3 flex items-center gap-1 text-xs text-slate-600 dark:text-slate-400">
                      <Clock className="w-3 h-3" />
                      {related.reading_time_minutes} min read
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        )}

        {/* CTA - adapts to site mode (waitlist / early access / live) */}
        <BlogCTA />
      </article>
    </PublicLayout>
  );
}
